// synthetic-logs.test.ts
import { describe, it, expect } from 'vitest';
import { syntheticLogs } from '../config/synthetic-logs';

describe('synthetic logs', () => {
  const logArray = (logs: any[]) => syntheticLogs(logs);

  it('should handle empty log array', () => {
    const result = logArray([]);
    expect(result).toBeDefined();
    expect(result.summary).toBeDefined();
  });

  // ... other tests ...
});

// synthetic-logs-data.test.ts
import { describe, it, expect } from 'vitest';
import { syntheticLogsData } from '../config/synthetic-logs-data';

describe('synthetic logs data', () => {
  const data = syntheticLogsData();

  it('should generate logs with different levels', () => {
    expect(data.logs).toBeDefined();
    expect(data.logs.length).toBeGreaterThan(0);
  });

  // ... other tests ...
});
```

This refactoring separates the tests into individual files and reduces the complexity of each test function.

